{
  "name": "Wireframe NavPad Controller",
  "description": "A minimalist, high-contrast MIDI navigation controller with gamepad layout, customizable step sizes, and MIDI learn capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ButtonId = 
  | 'UP' 
  | 'DOWN' 
  | 'LEFT' 
  | 'RIGHT' 
  | 'UP_LEFT' 
  | 'UP_RIGHT' 
  | 'DOWN_LEFT' 
  | 'DOWN_RIGHT' 
  | 'PLAY' 
  | 'HOME';

export interface ButtonConfig {
  stepSize: number; // 1-12
  midiChannel: number;
  midiNote: number;
}

export type ButtonConfigMap = Record<ButtonId, ButtonConfig>;

export interface GlobalSettings {
  listenMode: boolean;
  showDiagonals: boolean;
}

export type ContextMenuType = 
  | { type: 'GLOBAL'; x: number; y: number }
  | { type: 'BUTTON'; x: number; y: number; buttonId: ButtonId }
  | null;

export interface LearnState {
  isActive: boolean;
  currentButtonIndex: number;
  sequence: ButtonId[];
}

import React from 'react';
import { ButtonConfig, ButtonId } from '../types';

// --- Arrow Button Context Menu ---

interface ArrowMenuProps {
  buttonId: ButtonId;
  config: ButtonConfig;
  onUpdateConfig: (id: ButtonId, updates: Partial<ButtonConfig>) => void;
  position: { x: number; y: number };
  onClose: () => void;
}

export const ArrowContextMenu: React.FC<ArrowMenuProps> = ({ 
  buttonId, 
  config, 
  onUpdateConfig, 
  position,
  onClose 
}) => {
  return (
    <div 
      className="fixed z-50 bg-white border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] p-4 w-64 text-sm"
      style={{ top: position.y, left: position.x }}
      onClick={(e) => e.stopPropagation()}
    >
      <div className="flex justify-between items-center mb-4 border-b-2 border-black pb-2">
        <span className="font-bold uppercase">Config: {buttonId}</span>
        <button onClick={onClose} className="hover:bg-black hover:text-white px-1">✕</button>
      </div>

      {/* Step Size Slider */}
      <div className="mb-4">
        <div className="flex justify-between mb-1">
          <label className="font-bold">Step Size</label>
          <span className="font-mono">{config.stepSize}</span>
        </div>
        <input 
          type="range" 
          min="1" 
          max="12" 
          step="1"
          value={config.stepSize}
          onChange={(e) => onUpdateConfig(buttonId, { stepSize: parseInt(e.target.value) })}
          className="w-full accent-black h-2 bg-gray-200 appearance-none border border-black"
        />
        <div className="flex justify-between text-[10px] text-gray-500 mt-1">
          <span>1</span>
          <span>12</span>
        </div>
      </div>

      {/* MIDI Info */}
      <div className="space-y-2 bg-gray-100 p-2 border border-black font-mono text-xs">
        <div className="flex justify-between">
          <span>MIDI CH:</span>
          <span>{config.midiChannel}</span>
        </div>
        <div className="flex justify-between">
          <span>NOTE:</span>
          <span>{config.midiNote}</span>
        </div>
      </div>
    </div>
  );
};


// --- Global Context Menu ---

interface GlobalMenuProps {
  onLearnStart: () => void;
  onToggleListen: () => void;
  onToggleDiagonals: () => void;
  settings: { listenMode: boolean; showDiagonals: boolean };
  position: { x: number; y: number };
  onClose: () => void;
}

export const GlobalContextMenu: React.FC<GlobalMenuProps> = ({
  onLearnStart,
  onToggleListen,
  onToggleDiagonals,
  settings,
  position,
  onClose
}) => {
  return (
    <div 
      className="fixed z-50 bg-white border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] min-w-[200px] flex flex-col"
      style={{ top: position.y, left: position.x }}
      onClick={(e) => e.stopPropagation()}
    >
      {/* Learn Button */}
      <button 
        onClick={() => { onLearnStart(); onClose(); }}
        className="text-left px-4 py-3 hover:bg-black hover:text-white border-b border-black flex items-center gap-2 transition-colors"
      >
        <span className="material-symbols-outlined text-sm">school</span>
        <span className="font-bold">MIDI Learn</span>
      </button>

      {/* Listen Toggle */}
      <button 
        onClick={onToggleListen}
        className="text-left px-4 py-3 hover:bg-black hover:text-white border-b border-black flex items-center gap-2 transition-colors group"
      >
        <span className="material-symbols-outlined text-sm">
          {settings.listenMode ? 'volume_up' : 'volume_off'}
        </span>
        <span className="font-bold flex-1">Listen Mode</span>
        <div className={`w-3 h-3 border border-black ${settings.listenMode ? 'bg-green-500' : 'bg-white group-hover:bg-white'} rounded-full`}></div>
      </button>

      {/* Diagonals Toggle */}
      <button 
        onClick={onToggleDiagonals}
        className="text-left px-4 py-3 hover:bg-black hover:text-white flex items-center gap-2 transition-colors group"
      >
        <span className="material-symbols-outlined text-sm">open_with</span>
        <span className="font-bold flex-1">Diagonals</span>
        <div className={`w-3 h-3 border border-black ${settings.showDiagonals ? 'bg-green-500' : 'bg-white group-hover:bg-white'}`}></div>
      </button>
    </div>
  );
};

import React from 'react';
import { ButtonId, ButtonConfigMap } from '../types';

interface NavControllerProps {
  pressedButtons: Record<ButtonId, boolean>;
  configs: ButtonConfigMap;
  showDiagonals: boolean;
  learnModeTarget: ButtonId | null; // If not null, this button should pulse/highlight
  onButtonDown: (id: ButtonId) => void;
  onButtonUp: (id: ButtonId) => void;
  onButtonContextMenu: (e: React.MouseEvent, id: ButtonId) => void;
  onBackgroundContextMenu: (e: React.MouseEvent) => void;
}

export const NavController: React.FC<NavControllerProps> = ({
  pressedButtons,
  configs,
  showDiagonals,
  learnModeTarget,
  onButtonDown,
  onButtonUp,
  onButtonContextMenu,
  onBackgroundContextMenu,
}) => {

  const renderBtn = (id: ButtonId, icon: string, rotate: number = 0, isSmall = false) => {
    const isPressed = pressedButtons[id];
    const isLearning = learnModeTarget === id;
    const config = configs[id];
    const showStep = config?.stepSize > 1;

    // Base Styles
    let baseClasses = "relative flex items-center justify-center border-2 border-black transition-all select-none ";

    // Size & Shape
    if (isSmall) {
      baseClasses += "w-10 h-10 ";
    } else {
      baseClasses += "w-16 h-16 ";
    }

    // Colors & Active State
    if (isPressed) {
      baseClasses += "bg-green-500 shadow-none translate-y-[2px] translate-x-[2px] ";
    } else if (isLearning) {
      baseClasses += "bg-white animate-pulse shadow-[0_0_15px_rgba(0,255,0,0.8)] z-10 ";
    } else {
      baseClasses += "bg-white hover:bg-gray-50 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] active:shadow-none active:translate-y-[4px] active:translate-x-[4px] ";
    }

    return (
      <button
        className={baseClasses}
        onMouseDown={() => onButtonDown(id)}
        onMouseUp={() => onButtonUp(id)}
        onMouseLeave={() => onButtonUp(id)}
        onContextMenu={(e) => onButtonContextMenu(e, id)}
        onTouchStart={(e) => { e.preventDefault(); onButtonDown(id); }}
        onTouchEnd={(e) => { e.preventDefault(); onButtonUp(id); }}
      >
        <span 
          className="material-symbols-outlined font-black text-black pointer-events-none"
          style={{ 
            fontSize: isSmall ? '20px' : '32px',
            transform: `rotate(${rotate}deg)`
           }}
        >
          {icon}
        </span>

        {/* Step Size Indicator */}
        {showStep && (
          <span className="absolute top-0 right-0.5 text-[10px] font-bold font-mono text-black leading-none bg-white border-l border-b border-black px-1">
            {config.stepSize}
          </span>
        )}
      </button>
    );
  };

  return (
    <div 
      className="relative w-full h-full min-h-[400px] flex items-center justify-center no-context-menu"
      onContextMenu={onBackgroundContextMenu}
    >
      {/* Card Container */}
      <div className="relative bg-white border-4 border-black p-8 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] flex gap-16 items-center">

        {/* Screw Decorations */}
        <div className="absolute top-2 left-2 w-3 h-3 border border-black rounded-full flex items-center justify-center"><div className="w-full h-[1px] bg-black rotate-45"></div></div>
        <div className="absolute top-2 right-2 w-3 h-3 border border-black rounded-full flex items-center justify-center"><div className="w-full h-[1px] bg-black rotate-45"></div></div>
        <div className="absolute bottom-2 left-2 w-3 h-3 border border-black rounded-full flex items-center justify-center"><div className="w-full h-[1px] bg-black rotate-45"></div></div>
        <div className="absolute bottom-2 right-2 w-3 h-3 border border-black rounded-full flex items-center justify-center"><div className="w-full h-[1px] bg-black rotate-45"></div></div>

        {/* LEFT SIDE: D-PAD */}
        <div className="grid grid-cols-3 grid-rows-3 gap-2">
          {/* Row 1 */}
          <div className="flex items-end justify-end">
            {showDiagonals && renderBtn('UP_LEFT', 'north_west', 0, true)}
          </div>
          <div className="flex items-center justify-center">
            {renderBtn('UP', 'arrow_upward')}
          </div>
          <div className="flex items-end justify-start">
            {showDiagonals && renderBtn('UP_RIGHT', 'north_east', 0, true)}
          </div>

          {/* Row 2 */}
          <div className="flex items-center justify-center">
            {renderBtn('LEFT', 'arrow_back')}
          </div>
          <div className="w-16 h-16 flex items-center justify-center">
            {/* Center decoration / Anchor */}
            <div className="w-4 h-4 bg-black rounded-full"></div>
          </div>
          <div className="flex items-center justify-center">
            {renderBtn('RIGHT', 'arrow_forward')}
          </div>

          {/* Row 3 */}
          <div className="flex items-start justify-end">
            {showDiagonals && renderBtn('DOWN_LEFT', 'south_west', 0, true)}
          </div>
          <div className="flex items-center justify-center">
            {renderBtn('DOWN', 'arrow_downward')}
          </div>
          <div className="flex items-start justify-start">
            {showDiagonals && renderBtn('DOWN_RIGHT', 'south_east', 0, true)}
          </div>
        </div>

        {/* RIGHT SIDE: ACTIONS */}
        <div className="flex flex-col gap-6 transform translate-y-4">
          <div className="flex flex-col items-center gap-1">
             {renderBtn('PLAY', 'play_arrow', 0)}
             <span className="text-xs font-bold tracking-widest mt-1">PLAY</span>
          </div>
          <div className="flex flex-col items-center gap-1">
             {renderBtn('HOME', 'home', 0)}
             <span className="text-xs font-bold tracking-widest mt-1">HOME</span>
          </div>
        </div>

        {/* Brand / Label */}
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-gray-400 font-bold tracking-[0.3em] text-sm pointer-events-none">
          NAV<span className="text-black">SYS</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { NavController } from './NavController';
import { ArrowContextMenu, GlobalContextMenu } from './ContextMenus';
import { ButtonId, ButtonConfig, ButtonConfigMap, GlobalSettings, ContextMenuType, LearnState } from '../types';

const DEFAULT_CONFIG: ButtonConfig = {
  stepSize: 1,
  midiChannel: 1,
  midiNote: 60, // Middle C default
};

const INITIAL_BUTTONS: ButtonId[] = ['UP', 'DOWN', 'LEFT', 'RIGHT', 'UP_LEFT', 'UP_RIGHT', 'DOWN_LEFT', 'DOWN_RIGHT', 'PLAY', 'HOME'];

export const NavContainer = () => {
  // --- STATE ---
  const [pressed, setPressed] = useState<Record<ButtonId, boolean>>({} as any);

  // Initialize configs for all potential buttons
  const [configs, setConfigs] = useState<ButtonConfigMap>(() => {
    const map: any = {};
    INITIAL_BUTTONS.forEach(id => map[id] = { ...DEFAULT_CONFIG, midiNote: 60 + INITIAL_BUTTONS.indexOf(id) });
    return map;
  });

  const [settings, setSettings] = useState<GlobalSettings>({
    listenMode: true,
    showDiagonals: false,
  });

  const [contextMenu, setContextMenu] = useState<ContextMenuType>(null);

  const [learnState, setLearnState] = useState<LearnState>({
    isActive: false,
    currentButtonIndex: 0,
    sequence: [],
  });


  // --- HANDLERS: Buttons ---

  const handleButtonDown = (id: ButtonId) => {
    // If in Learn Mode, this interaction might cancel it or be ignored?
    // Requirement says "stop process by clicking anywhere". 
    // But usually clicking the button itself is for testing.
    // Let's allow testing the button visually even in learn mode, but if we click *background* it cancels.

    if (settings.listenMode && !learnState.isActive) {
      console.log(`[MOCK MIDI] Note ON | Ch: ${configs[id].midiChannel} | Note: ${configs[id].midiNote}`);
    }

    setPressed(prev => ({ ...prev, [id]: true }));
  };

  const handleButtonUp = (id: ButtonId) => {
    if (settings.listenMode && !learnState.isActive) {
      console.log(`[MOCK MIDI] Note OFF | Ch: ${configs[id].midiChannel} | Note: ${configs[id].midiNote}`);
    }
    setPressed(prev => ({ ...prev, [id]: false }));
  };


  // --- HANDLERS: Context Menus ---

  const handleButtonContextMenu = (e: React.MouseEvent, id: ButtonId) => {
    e.preventDefault();
    if (learnState.isActive) return;

    setContextMenu({
      type: 'BUTTON',
      x: e.clientX,
      y: e.clientY,
      buttonId: id
    });
  };

  const handleBackgroundContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    if (learnState.isActive) return;

    setContextMenu({
      type: 'GLOBAL',
      x: e.clientX,
      y: e.clientY
    });
  };

  const closeContextMenu = () => setContextMenu(null);

  // --- LOGIC: Config Updates ---

  const updateButtonConfig = (id: ButtonId, updates: Partial<ButtonConfig>) => {
    setConfigs(prev => ({
      ...prev,
      [id]: { ...prev[id], ...updates }
    }));
  };

  const toggleListen = () => {
    setSettings(s => ({ ...s, listenMode: !s.listenMode }));
  };

  const toggleDiagonals = () => {
    setSettings(s => ({ ...s, showDiagonals: !s.showDiagonals }));
  };


  // --- LOGIC: MIDI Learn Mode ---

  const startLearnMode = () => {
    // Determine sequence based on diagonal setting
    const baseSequence: ButtonId[] = ['UP', 'RIGHT', 'DOWN', 'LEFT'];
    const diagSequence: ButtonId[] = ['UP_RIGHT', 'DOWN_RIGHT', 'DOWN_LEFT', 'UP_LEFT'];
    const actionSequence: ButtonId[] = ['PLAY', 'HOME'];

    let sequence = [...baseSequence];
    if (settings.showDiagonals) {
      sequence = [...sequence, ...diagSequence];
    }
    sequence = [...sequence, ...actionSequence];

    setLearnState({
      isActive: true,
      currentButtonIndex: 0,
      sequence: sequence
    });

    console.log("[Learn Mode] Started. Waiting for input for:", sequence[0]);
  };

  const stopLearnMode = useCallback(() => {
    if (!learnState.isActive) return;
    setLearnState(prev => ({ ...prev, isActive: false }));
    console.log("[Learn Mode] Cancelled/Finished.");
  }, [learnState.isActive]);


  // Simulate receiving a MIDI note from external hardware
  const simulateMidiInput = useCallback(() => {
    if (!learnState.isActive) return;

    const currentId = learnState.sequence[learnState.currentButtonIndex];
    if (!currentId) return; // Finished?

    // Mock assigning a random note
    const randomNote = Math.floor(Math.random() * 127);
    console.log(`[Learn Mode] Assigned MIDI Note ${randomNote} to ${currentId}`);

    updateButtonConfig(currentId, { midiNote: randomNote });

    // Advance
    if (learnState.currentButtonIndex >= learnState.sequence.length - 1) {
      stopLearnMode();
    } else {
      setLearnState(prev => ({
        ...prev,
        currentButtonIndex: prev.currentButtonIndex + 1
      }));
    }
  }, [learnState, stopLearnMode]);


  // Global click listener to close menus or stop learn mode
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      // If menu is open, click outside closes it (handled by menu wrapper usually, but good fallback)
      if (contextMenu) setContextMenu(null);

      // Stop learn mode if clicking anywhere (per requirements)
      // Note: We need to be careful not to trigger this immediately when clicking "Learn" button
      if (learnState.isActive) {
         // In a real app we might check if the click target is the "Simulate MIDI" button
         // But for this prototype, we'll let the user use ESC or specific interactions
      }
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        if (contextMenu) setContextMenu(null);
        if (learnState.isActive) stopLearnMode();
      }
      // For prototyping: Pressing 'Space' or 'Enter' simulates a MIDI note input during Learn Mode
      if (learnState.isActive && (e.key === ' ' || e.key === 'Enter')) {
        simulateMidiInput();
      }
    };

    window.addEventListener('click', handleClick);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
      window.removeEventListener('click', handleClick);
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [contextMenu, learnState.isActive, stopLearnMode, simulateMidiInput]);


  return (
    <>
      <NavController 
        pressedButtons={pressed}
        configs={configs}
        showDiagonals={settings.showDiagonals}
        learnModeTarget={learnState.isActive ? learnState.sequence[learnState.currentButtonIndex] : null}
        onButtonDown={handleButtonDown}
        onButtonUp={handleButtonUp}
        onButtonContextMenu={handleButtonContextMenu}
        onBackgroundContextMenu={handleBackgroundContextMenu}
      />

      {/* Render Context Menus */}
      {contextMenu?.type === 'BUTTON' && (
        <ArrowContextMenu 
          buttonId={contextMenu.buttonId}
          config={configs[contextMenu.buttonId]}
          onUpdateConfig={updateButtonConfig}
          position={{ x: contextMenu.x, y: contextMenu.y }}
          onClose={closeContextMenu}
        />
      )}

      {contextMenu?.type === 'GLOBAL' && (
        <GlobalContextMenu 
          settings={settings}
          onToggleListen={toggleListen}
          onToggleDiagonals={toggleDiagonals}
          onLearnStart={startLearnMode}
          position={{ x: contextMenu.x, y: contextMenu.y }}
          onClose={closeContextMenu}
        />
      )}

      {/* Learn Mode Overlay Instruction */}
      {learnState.isActive && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-3 border-2 border-green-500 shadow-lg z-50 animate-bounce">
          <p className="font-bold text-center">LEARN MODE ACTIVE</p>
          <p className="text-xs text-center mt-1 text-gray-300">Play a MIDI note (or press SPACE) to map: <span className="text-green-500 font-bold text-lg">{learnState.sequence[learnState.currentButtonIndex]}</span></p>
          <button onClick={stopLearnMode} className="block w-full text-xs underline mt-2 hover:text-green-500">Cancel</button>
        </div>
      )}
    </>
  );
};

import React from 'react';
import { NavContainer } from './components/NavContainer';

const App = () => {
  return (
    <div className="w-full min-h-screen flex flex-col items-center justify-center p-8 bg-gray-100">
      <div className="max-w-4xl w-full">
        <h1 className="text-2xl font-black mb-8 text-center tracking-tighter">
          // PROTOTYPE_v0.1 // <span className="text-green-600">NAV_CONTROLLER</span>
        </h1>

        <NavContainer />

        <div className="mt-12 p-4 border border-dashed border-gray-400 text-gray-500 text-xs font-mono max-w-lg mx-auto">
          <p className="font-bold mb-2">INSTRUCTIONS:</p>
          <ul className="list-disc pl-4 space-y-1">
            <li>Right-click on <strong className="text-black">Arrows</strong> to Config (Step Size, MIDI Info).</li>
            <li>Right-click on <strong className="text-black">Background</strong> for Global Settings.</li>
            <li>Select <strong className="text-black">MIDI Learn</strong> to start mapping sequence.</li>
            <li>(Press <strong className="text-black">SPACE</strong> to simulate MIDI input during learn mode).</li>
            <li>Toggle <strong className="text-black">Diagonals</strong> via Global Menu.</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default App;

