export type ButtonId = 
  | 'UP' 
  | 'DOWN' 
  | 'LEFT' 
  | 'RIGHT' 
  | 'UP_LEFT' 
  | 'UP_RIGHT' 
  | 'DOWN_LEFT' 
  | 'DOWN_RIGHT' 
  | 'PLAY' 
  | 'HOME';

export interface ButtonConfig {
  stepSize: number; // 1-12
  midiChannel: number;
  midiNote: number;
}

export type ButtonConfigMap = Record<ButtonId, ButtonConfig>;

export interface GlobalSettings {
  listenMode: boolean;
  showDiagonals: boolean;
  showActions: boolean;
}

export type ContextMenuType = 
  | { type: 'GLOBAL'; x: number; y: number }
  | { type: 'BUTTON'; x: number; y: number; buttonId: ButtonId }
  | null;

export interface LearnState {
  isActive: boolean;
  currentButtonIndex: number;
  sequence: ButtonId[];
}

import React, { useState, useEffect, useCallback } from 'react';
import { NavController } from './NavController';
import { ArrowContextMenu, GlobalContextMenu } from './ContextMenus';
import { ButtonId, ButtonConfig, ButtonConfigMap, GlobalSettings, ContextMenuType, LearnState } from '../types';

const DEFAULT_CONFIG: ButtonConfig = {
  stepSize: 1,
  midiChannel: 1,
  midiNote: 60, // Middle C default
};

const INITIAL_BUTTONS: ButtonId[] = ['UP', 'DOWN', 'LEFT', 'RIGHT', 'UP_LEFT', 'UP_RIGHT', 'DOWN_LEFT', 'DOWN_RIGHT', 'PLAY', 'HOME'];

export const NavContainer = () => {
  // --- STATE ---
  const [pressed, setPressed] = useState<Record<ButtonId, boolean>>({} as any);

  // Initialize configs for all potential buttons
  const [configs, setConfigs] = useState<ButtonConfigMap>(() => {
    const map: any = {};
    INITIAL_BUTTONS.forEach(id => map[id] = { ...DEFAULT_CONFIG, midiNote: 60 + INITIAL_BUTTONS.indexOf(id) });
    return map;
  });

  const [settings, setSettings] = useState<GlobalSettings>({
    listenMode: true,
    showDiagonals: false,
    showActions: true,
  });

  const [contextMenu, setContextMenu] = useState<ContextMenuType>(null);

  const [learnState, setLearnState] = useState<LearnState>({
    isActive: false,
    currentButtonIndex: 0,
    sequence: [],
  });


  // --- HANDLERS: Buttons ---

  const handleButtonDown = (id: ButtonId) => {
    if (settings.listenMode && !learnState.isActive) {
      console.log(`[MOCK MIDI] Note ON | Ch: ${configs[id].midiChannel} | Note: ${configs[id].midiNote}`);
    }
    setPressed(prev => ({ ...prev, [id]: true }));
  };

  const handleButtonUp = (id: ButtonId) => {
    if (settings.listenMode && !learnState.isActive) {
      console.log(`[MOCK MIDI] Note OFF | Ch: ${configs[id].midiChannel} | Note: ${configs[id].midiNote}`);
    }
    setPressed(prev => ({ ...prev, [id]: false }));
  };


  // --- HANDLERS: Context Menus ---

  const handleButtonContextMenu = (e: React.MouseEvent, id: ButtonId) => {
    e.preventDefault();
    e.stopPropagation(); // CRITICAL: Prevents bubbling to background handler

    if (learnState.isActive) return;

    setContextMenu({
      type: 'BUTTON',
      x: e.clientX,
      y: e.clientY,
      buttonId: id
    });
  };

  const handleBackgroundContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    if (learnState.isActive) return;

    setContextMenu({
      type: 'GLOBAL',
      x: e.clientX,
      y: e.clientY
    });
  };

  const closeContextMenu = () => setContextMenu(null);

  // --- LOGIC: Config Updates ---

  const updateButtonConfig = (id: ButtonId, updates: Partial<ButtonConfig>) => {
    setConfigs(prev => ({
      ...prev,
      [id]: { ...prev[id], ...updates }
    }));
  };

  const toggleListen = () => {
    setSettings(s => ({ ...s, listenMode: !s.listenMode }));
  };

  const toggleDiagonals = () => {
    setSettings(s => ({ ...s, showDiagonals: !s.showDiagonals }));
  };

  const toggleActions = () => {
    setSettings(s => ({ ...s, showActions: !s.showActions }));
  };


  // --- LOGIC: MIDI Learn Mode ---

  const startLearnMode = () => {
    // Determine sequence based on diagonal setting
    const baseSequence: ButtonId[] = ['UP', 'RIGHT', 'DOWN', 'LEFT'];
    const diagSequence: ButtonId[] = ['UP_RIGHT', 'DOWN_RIGHT', 'DOWN_LEFT', 'UP_LEFT'];
    const actionSequence: ButtonId[] = ['PLAY', 'HOME'];

    let sequence = [...baseSequence];
    if (settings.showDiagonals) {
      sequence = [...sequence, ...diagSequence];
    }
    // Only learn actions if they are visible
    if (settings.showActions) {
      sequence = [...sequence, ...actionSequence];
    }

    setLearnState({
      isActive: true,
      currentButtonIndex: 0,
      sequence: sequence
    });

    console.log("[Learn Mode] Started. Waiting for input for:", sequence[0]);
  };

  const stopLearnMode = useCallback(() => {
    if (!learnState.isActive) return;
    setLearnState(prev => ({ ...prev, isActive: false }));
    console.log("[Learn Mode] Cancelled/Finished.");
  }, [learnState.isActive]);


  // Simulate receiving a MIDI note from external hardware
  const simulateMidiInput = useCallback(() => {
    if (!learnState.isActive) return;

    const currentId = learnState.sequence[learnState.currentButtonIndex];
    if (!currentId) return; // Finished?

    // Mock assigning a random note
    const randomNote = Math.floor(Math.random() * 127);
    console.log(`[Learn Mode] Assigned MIDI Note ${randomNote} to ${currentId}`);

    updateButtonConfig(currentId, { midiNote: randomNote });

    // Advance
    if (learnState.currentButtonIndex >= learnState.sequence.length - 1) {
      stopLearnMode();
    } else {
      setLearnState(prev => ({
        ...prev,
        currentButtonIndex: prev.currentButtonIndex + 1
      }));
    }
  }, [learnState, stopLearnMode]);


  // Global click listener to close menus
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      // If menu is open, click outside closes it
      if (contextMenu) setContextMenu(null);
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        if (contextMenu) setContextMenu(null);
        if (learnState.isActive) stopLearnMode();
      }
      // Pressing 'Space' or 'Enter' simulates a MIDI note input during Learn Mode
      if (learnState.isActive && (e.key === ' ' || e.key === 'Enter')) {
        simulateMidiInput();
      }
    };

    window.addEventListener('click', handleClick);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
      window.removeEventListener('click', handleClick);
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [contextMenu, learnState.isActive, stopLearnMode, simulateMidiInput]);


  return (
    <>
      <NavController 
        pressedButtons={pressed}
        configs={configs}
        showDiagonals={settings.showDiagonals}
        showActions={settings.showActions}
        onToggleActions={toggleActions}
        learnModeTarget={learnState.isActive ? learnState.sequence[learnState.currentButtonIndex] : null}
        onButtonDown={handleButtonDown}
        onButtonUp={handleButtonUp}
        onButtonContextMenu={handleButtonContextMenu}
        onBackgroundContextMenu={handleBackgroundContextMenu}
      />

      {/* Render Context Menus */}
      {contextMenu?.type === 'BUTTON' && (
        <ArrowContextMenu 
          buttonId={contextMenu.buttonId}
          config={configs[contextMenu.buttonId]}
          onUpdateConfig={updateButtonConfig}
          position={{ x: contextMenu.x, y: contextMenu.y }}
          onClose={closeContextMenu}
        />
      )}

      {contextMenu?.type === 'GLOBAL' && (
        <GlobalContextMenu 
          settings={settings}
          onToggleListen={toggleListen}
          onToggleDiagonals={toggleDiagonals}
          onLearnStart={startLearnMode}
          position={{ x: contextMenu.x, y: contextMenu.y }}
          onClose={closeContextMenu}
        />
      )}

      {/* Learn Mode Overlay Instruction */}
      {learnState.isActive && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-3 border-2 border-yellow-400 shadow-lg z-50 animate-bounce">
          <p className="font-bold text-center">LEARN MODE ACTIVE</p>
          <p className="text-xs text-center mt-1 text-gray-300">Play a MIDI note (or press SPACE) to map: <span className="text-yellow-400 font-bold text-lg">{learnState.sequence[learnState.currentButtonIndex]}</span></p>
          <button onClick={stopLearnMode} className="block w-full text-xs underline mt-2 hover:text-yellow-400">Cancel</button>
        </div>
      )}
    </>
  );
};

import React from 'react';
import { ButtonId, ButtonConfigMap } from '../types';

interface NavControllerProps {
  pressedButtons: Record<ButtonId, boolean>;
  configs: ButtonConfigMap;
  showDiagonals: boolean;
  showActions: boolean;
  onToggleActions: () => void;
  learnModeTarget: ButtonId | null; // If not null, this button should pulse/highlight
  onButtonDown: (id: ButtonId) => void;
  onButtonUp: (id: ButtonId) => void;
  onButtonContextMenu: (e: React.MouseEvent, id: ButtonId) => void;
  onBackgroundContextMenu: (e: React.MouseEvent) => void;
}

export const NavController: React.FC<NavControllerProps> = ({
  pressedButtons,
  configs,
  showDiagonals,
  showActions,
  onToggleActions,
  learnModeTarget,
  onButtonDown,
  onButtonUp,
  onButtonContextMenu,
  onBackgroundContextMenu,
}) => {

  // Render SVG Arrow Button (Directional)
  const renderArrowBtn = (id: ButtonId, rotate: number) => {
    const isPressed = pressedButtons[id];
    const isLearning = learnModeTarget === id;
    const config = configs[id];
    const showStep = config?.stepSize > 1;
    const isDiagonal = ['UP_LEFT', 'UP_RIGHT', 'DOWN_LEFT', 'DOWN_RIGHT'].includes(id);
    const btnSize = isDiagonal ? 'w-10 h-10' : 'w-14 h-14';

    // SVG Path for a block arrow
    const arrowPath = "M50 5 L90 45 L70 45 L70 95 L30 95 L30 45 L10 45 Z";

    // Animation / Transform constants
    const pressTransform = isPressed ? 'translate(2px, 2px)' : 'translate(0, 0)'; // Reduced movement for smaller size
    const transition = isPressed ? 'all 0.05s ease-out' : 'all 0.1s ease-out';

    // Dynamic Styles for the SVG element (Visuals)
    const svgStyle: React.CSSProperties = {
      filter: isPressed ? 'none' : 'drop-shadow(3px 3px 0px #000)',
      transform: pressTransform,
      transition: transition,
      cursor: 'pointer',
    };

    // Style for the label to move with the button press
    const labelStyle: React.CSSProperties = {
      transform: pressTransform,
      transition: transition,
    };

    const fillColor = isPressed ? '#22c55e' : 'white'; 
    const strokeColor = isLearning ? '#facc15' : 'black';
    const strokeWidth = isLearning ? 6 : 3;

    return (
      <button
        className={`relative ${btnSize} flex items-center justify-center outline-none select-none touch-none group bg-transparent border-none p-0 focus:outline-none`}
        onMouseDown={() => onButtonDown(id)}
        onMouseUp={() => onButtonUp(id)}
        onMouseLeave={() => onButtonUp(id)}
        onContextMenu={(e) => onButtonContextMenu(e, id)}
        onTouchStart={(e) => { e.preventDefault(); onButtonDown(id); }}
        onTouchEnd={(e) => { e.preventDefault(); onButtonUp(id); }}
      >
        <svg 
            viewBox="0 0 100 100" 
            className={`w-full h-full overflow-visible ${isLearning ? 'animate-pulse' : ''}`}
            style={svgStyle}
        >
            <path 
                d={arrowPath} 
                fill={fillColor} 
                stroke={strokeColor}
                strokeWidth={strokeWidth}
                strokeLinejoin="round"
                transform={`rotate(${rotate} 50 50)`} 
            />
        </svg>

        {/* Step Size Indicator - Centered on the arrow */}
        {showStep && (
          <div 
            className="absolute inset-0 flex items-center justify-center pointer-events-none z-20"
            style={labelStyle}
          >
            <div className={`bg-black text-white ${isDiagonal ? 'text-[8px] w-4 h-4' : 'text-[10px] w-5 h-5'} font-bold font-mono border border-white flex items-center justify-center rounded-full shadow-sm`}>
              {config.stepSize}
            </div>
          </div>
        )}
      </button>
    );
  };

  // Render Circular Button (Actions: Play, Home)
  const renderCircleBtn = (id: ButtonId, icon: string) => {
    const isPressed = pressedButtons[id];
    const isLearning = learnModeTarget === id;

    // Compact size w-12 (48px)
    // Decreased border thickness: border-2 -> border (1px)
    let baseClasses = "relative w-12 h-12 flex items-center justify-center border border-black rounded-full transition-all select-none ";

    if (isPressed) {
      baseClasses += "bg-green-500 shadow-none translate-y-[2px] translate-x-[2px] ";
    } else if (isLearning) {
      baseClasses += "bg-white animate-pulse shadow-[0_0_15px_rgba(250,204,21,0.9)] z-10 "; 
    } else {
      baseClasses += "bg-white hover:bg-gray-50 shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] active:shadow-none active:translate-y-[3px] active:translate-x-[3px] ";
    }

    return (
      <button
        className={baseClasses}
        onMouseDown={() => onButtonDown(id)}
        onMouseUp={() => onButtonUp(id)}
        onMouseLeave={() => onButtonUp(id)}
        onContextMenu={(e) => onButtonContextMenu(e, id)}
        onTouchStart={(e) => { e.preventDefault(); onButtonDown(id); }}
        onTouchEnd={(e) => { e.preventDefault(); onButtonUp(id); }}
      >
        {/* Increased icon size: text-xl -> text-3xl. Decreased thickness: removed font-black */}
        <span className="material-symbols-outlined text-black pointer-events-none text-3xl">
          {icon}
        </span>
      </button>
    );
  };

  return (
    <div 
      className="relative w-full h-full min-h-[300px] flex items-center justify-center no-context-menu"
      onContextMenu={onBackgroundContextMenu}
    >
      {/* Card Container - Compacted padding and rounded corners */}
      <div className="relative bg-white p-8 rounded-[2.5rem] shadow-[0_20px_40px_-10px_rgba(0,0,0,0.1)] flex gap-0 items-stretch transition-all duration-300">

        {/* LEFT SIDE: D-PAD */}
        <div className="grid grid-cols-3 grid-rows-3 gap-0">
          {/* Row 1 */}
          <div className="flex items-end justify-end">
            {showDiagonals && renderArrowBtn('UP_LEFT', 315)}
          </div>
          <div className="flex items-center justify-center">
            {renderArrowBtn('UP', 0)}
          </div>
          <div className="flex items-end justify-start">
            {showDiagonals && renderArrowBtn('UP_RIGHT', 45)}
          </div>

          {/* Row 2 */}
          <div className="flex items-center justify-center">
            {renderArrowBtn('LEFT', 270)}
          </div>
          <div className="w-14 h-14 flex items-center justify-center">
             {/* Center cell - matches cardinal button size to keep grid tight */}
          </div>
          <div className="flex items-center justify-center">
            {renderArrowBtn('RIGHT', 90)}
          </div>

          {/* Row 3 */}
          <div className="flex items-start justify-end">
            {showDiagonals && renderArrowBtn('DOWN_LEFT', 225)}
          </div>
          <div className="flex items-center justify-center">
            {renderArrowBtn('DOWN', 180)}
          </div>
          <div className="flex items-start justify-start">
            {showDiagonals && renderArrowBtn('DOWN_RIGHT', 135)}
          </div>
        </div>

        {/* MIDDLE: Toggle Handle */}
        <div className="flex items-center justify-center px-1">
          <button 
            onClick={onToggleActions}
            className="w-4 h-16 rounded-full hover:bg-gray-100 flex items-center justify-center text-gray-300 hover:text-black transition-colors outline-none"
            title={showActions ? "Collapse Actions" : "Show Actions"}
          >
             <span className="material-symbols-outlined text-sm font-bold">
               {showActions ? 'chevron_left' : 'chevron_right'}
             </span>
          </button>
        </div>

        {/* RIGHT SIDE: ACTIONS - Collapsible */}
        <div 
          className={`flex flex-col justify-center overflow-hidden transition-all duration-300 ease-in-out ${showActions ? 'w-16 opacity-100 ml-1' : 'w-0 opacity-0 ml-0'}`}
        >
          <div className="flex flex-col gap-3 min-w-[3rem]">
            <div className="flex flex-col items-center gap-0">
               {renderCircleBtn('PLAY', 'play_arrow')}
            </div>
            <div className="flex flex-col items-center gap-0">
               {renderCircleBtn('HOME', 'home')}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

